import{_ as a,c as e,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Режимы Diff: Многоракурсный анализ изменений | Plannotator","description":"Узнайте, как переключать типы diff в Plannotator для код-ревью. Выбирайте uncommitted, staged, last commit или branch в выпадающем меню для анализа изменений с разных ракурсов.","frontmatter":{"title":"Режимы Diff: Многоракурсный анализ изменений | Plannotator","sidebarTitle":"5 режимов просмотра diff","subtitle":"Режимы Diff: Многоракурсный анализ изменений","description":"Узнайте, как переключать типы diff в Plannotator для код-ревью. Выбирайте uncommitted, staged, last commit или branch в выпадающем меню для анализа изменений с разных ракурсов.","tags":["code-review","git","diff","tutorial"],"prerequisite":["code-review-basics"],"order":6},"headers":[],"relativePath":"ru/backnotprop/plannotator/platforms/code-review-diff-types/index.md","filePath":"ru/backnotprop/plannotator/platforms/code-review-diff-types/index.md"}'),d={name:"ru/backnotprop/plannotator/platforms/code-review-diff-types/index.md"};function r(s,t,n,l,p,c){return i(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="переключение-режимов-diff" tabindex="-1">Переключение режимов Diff <a class="header-anchor" href="#переключение-режимов-diff" aria-label="Permalink to &quot;Переключение режимов Diff&quot;">​</a></h1><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><p>При проведении код-ревью вы сможете:</p><ul><li>Быстро переключаться между 5 режимами diff через выпадающее меню</li><li>Понимать, какой диапазон изменений показывает каждый режим</li><li>Выбирать подходящий тип diff в зависимости от задачи ревью</li><li>Избегать пропуска важных изменений из-за неправильного выбора режима</li></ul><h2 id="типичные-проблемы" tabindex="-1">Типичные проблемы <a class="header-anchor" href="#типичные-проблемы" aria-label="Permalink to &quot;Типичные проблемы&quot;">​</a></h2><p><strong>При ревью видите только рабочую директорию и пропускаете staged-файлы</strong>:</p><p>Вы запускаете команду <code>/plannotator-review</code>, видите изменения кода, добавляете комментарии. Но после коммита обнаруживаете, что в ревью не попали файлы, уже добавленные в staging area через <code>git add</code> — они вообще не отображались в diff.</p><p><strong>Хотите увидеть общую разницу между текущей веткой и main</strong>:</p><p>Вы разрабатываете feature-ветку несколько недель и хотите посмотреть все изменения в целом, но режим «незакоммиченные изменения» по умолчанию показывает только правки за последние дни.</p><p><strong>Хотите сравнить два конкретных коммита</strong>:</p><p>Вам нужно убедиться, что баг-фикс корректен, и сравнить код до и после исправления, но вы не знаете, как заставить Plannotator показать diff исторических коммитов.</p><h2 id="когда-это-пригодится" tabindex="-1">Когда это пригодится <a class="header-anchor" href="#когда-это-пригодится" aria-label="Permalink to &quot;Когда это пригодится&quot;">​</a></h2><ul><li><strong>При полном ревью</strong>: одновременный просмотр изменений в рабочей директории и staging area</li><li><strong>Перед слиянием ветки</strong>: проверка всех изменений текущей ветки относительно main/master</li><li><strong>При ревью отката</strong>: проверка, какие файлы изменил последний коммит</li><li><strong>При командной работе</strong>: проверка кода коллег, добавленного в staging, но ещё не закоммиченного</li></ul><h2 id="ключевая-идея" tabindex="-1">Ключевая идея <a class="header-anchor" href="#ключевая-идея" aria-label="Permalink to &quot;Ключевая идея&quot;">​</a></h2><p>У команды git diff много вариантов, каждый показывает разный диапазон кода. Plannotator собрал их в одном выпадающем меню, чтобы вам не нужно было запоминать сложные git-команды.</p><div class="info custom-block"><p class="custom-block-title">Справочник типов Git Diff</p><table tabindex="0"><thead><tr><th>Тип diff</th><th>Диапазон</th><th>Типичный сценарий</th></tr></thead><tbody><tr><td>Uncommitted changes</td><td>Рабочая директория + staging</td><td>Ревью всех изменений текущей разработки</td></tr><tr><td>Staged changes</td><td>Только staging</td><td>Проверка перед коммитом</td></tr><tr><td>Unstaged changes</td><td>Только рабочая директория</td><td>Ревью изменений без <code>git add</code></td></tr><tr><td>Last commit</td><td>Последний коммит</td><td>Откат или проверка недавнего коммита</td></tr><tr><td>vs main</td><td>Текущая ветка vs основная</td><td>Полная проверка перед слиянием</td></tr></tbody></table></div><p>Опции в выпадающем меню динамически меняются в зависимости от состояния Git:</p><ul><li>Если вы не на основной ветке, появится опция «vs main»</li><li>Если нет staged-файлов, режим Staged покажет «No staged changes»</li></ul><h2 id="пошаговая-инструкция" tabindex="-1">Пошаговая инструкция <a class="header-anchor" href="#пошаговая-инструкция" aria-label="Permalink to &quot;Пошаговая инструкция&quot;">​</a></h2><h3 id="шаг-1-запустите-код-ревью" tabindex="-1">Шаг 1: Запустите код-ревью <a class="header-anchor" href="#шаг-1-запустите-код-ревью" aria-label="Permalink to &quot;Шаг 1: Запустите код-ревью&quot;">​</a></h3><p><strong>Зачем</strong></p><p>Сначала нужно открыть интерфейс код-ревью Plannotator.</p><p><strong>Действие</strong></p><p>Выполните в терминале:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>Ожидаемый результат</strong></p><p>В браузере откроется страница код-ревью. Над деревом файлов слева будет выпадающее меню с текущим типом diff (обычно «Uncommitted changes»).</p><h3 id="шаг-2-переключитесь-на-режим-staged" tabindex="-1">Шаг 2: Переключитесь на режим Staged <a class="header-anchor" href="#шаг-2-переключитесь-на-режим-staged" aria-label="Permalink to &quot;Шаг 2: Переключитесь на режим Staged&quot;">​</a></h3><p><strong>Зачем</strong></p><p>Чтобы увидеть файлы, добавленные через <code>git add</code>, но ещё не закоммиченные.</p><p><strong>Действие</strong></p><ol><li>Нажмите на выпадающее меню над деревом файлов слева</li><li>Выберите «Staged changes»</li></ol><p><strong>Ожидаемый результат</strong></p><ul><li>Если есть staged-файлы, они отобразятся в дереве файлов</li><li>Если staged-файлов нет, в основной области появится: «No staged changes. Stage some files with git add.»</li></ul><h3 id="шаг-3-переключитесь-на-режим-last-commit" tabindex="-1">Шаг 3: Переключитесь на режим Last Commit <a class="header-anchor" href="#шаг-3-переключитесь-на-режим-last-commit" aria-label="Permalink to &quot;Шаг 3: Переключитесь на режим Last Commit&quot;">​</a></h3><p><strong>Зачем</strong></p><p>Чтобы проверить только что закоммиченный код и убедиться в отсутствии проблем.</p><p><strong>Действие</strong></p><ol><li>Снова откройте выпадающее меню</li><li>Выберите «Last commit»</li></ol><p><strong>Ожидаемый результат</strong></p><ul><li>Отобразятся все файлы, изменённые в последнем коммите</li><li>Содержимое diff — это разница <code>HEAD~1..HEAD</code></li></ul><h3 id="шаг-4-переключитесь-на-режим-vs-main-если-доступен" tabindex="-1">Шаг 4: Переключитесь на режим vs main (если доступен) <a class="header-anchor" href="#шаг-4-переключитесь-на-режим-vs-main-если-доступен" aria-label="Permalink to &quot;Шаг 4: Переключитесь на режим vs main (если доступен)&quot;">​</a></h3><p><strong>Зачем</strong></p><p>Чтобы увидеть все изменения текущей ветки относительно основной.</p><p><strong>Действие</strong></p><ol><li>Проверьте, есть ли в выпадающем меню опция «vs main» или «vs master»</li><li>Если есть, выберите её</li></ol><p><strong>Ожидаемый результат</strong></p><ul><li>В дереве файлов отобразятся все файлы с различиями между текущей и основной веткой</li><li>Содержимое diff — полные изменения <code>main..HEAD</code></li></ul><div class="tip custom-block"><p class="custom-block-title">Проверка текущей ветки</p><p>Если не видите опцию «vs main», значит вы на основной ветке. Проверьте текущую ветку командой:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rev-parse</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --abbrev-ref</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD</span></span></code></pre></div><p>Переключитесь на feature-ветку и попробуйте снова:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div></div><h2 id="контрольныи-список-✅" tabindex="-1">Контрольный список ✅ <a class="header-anchor" href="#контрольныи-список-✅" aria-label="Permalink to &quot;Контрольный список ✅&quot;">​</a></h2><p>Убедитесь, что вы освоили:</p><ul><li>[ ] Умеете находить и открывать выпадающее меню типов diff</li><li>[ ] Понимаете разницу между «Uncommitted», «Staged» и «Last commit»</li><li>[ ] Знаете, когда появляется опция «vs main»</li><li>[ ] Понимаете, какой тип diff использовать в каждом сценарии</li></ul><h2 id="типичные-ошибки" tabindex="-1">Типичные ошибки <a class="header-anchor" href="#типичные-ошибки" aria-label="Permalink to &quot;Типичные ошибки&quot;">​</a></h2><h3 id="ошибка-1-при-ревью-смотрите-только-uncommitted-и-пропускаете-staged-фаилы" tabindex="-1">Ошибка 1: При ревью смотрите только Uncommitted и пропускаете Staged-файлы <a class="header-anchor" href="#ошибка-1-при-ревью-смотрите-только-uncommitted-и-пропускаете-staged-фаилы" aria-label="Permalink to &quot;Ошибка 1: При ревью смотрите только Uncommitted и пропускаете Staged-файлы&quot;">​</a></h3><p><strong>Симптом</strong></p><p>После коммита обнаруживаете, что в ревью пропустили некоторые staged-файлы.</p><p><strong>Причина</strong></p><p>Режим Uncommitted показывает все изменения в рабочей директории и staging area (<code>git diff HEAD</code>), staged-файлы тоже включены.</p><p><strong>Решение</strong></p><p>Перед ревью сначала проверьте режим Staged или используйте Uncommitted (включает staging area).</p><h3 id="ошибка-2-перед-слиянием-ветки-не-сравнили-с-main" tabindex="-1">Ошибка 2: Перед слиянием ветки не сравнили с main <a class="header-anchor" href="#ошибка-2-перед-слиянием-ветки-не-сравнили-с-main" aria-label="Permalink to &quot;Ошибка 2: Перед слиянием ветки не сравнили с main&quot;">​</a></h3><p><strong>Симптом</strong></p><p>После слияния в main обнаруживаете, что попали несвязанные изменения.</p><p><strong>Причина</strong></p><p>Смотрели только коммиты за последние дни, не сравнивая всю ветку с main.</p><p><strong>Решение</strong></p><p>Перед слиянием проведите полную проверку в режиме «vs main».</p><h3 id="ошибка-3-боитесь-что-переключение-режима-удалит-комментарии" tabindex="-1">Ошибка 3: Боитесь, что переключение режима удалит комментарии <a class="header-anchor" href="#ошибка-3-боитесь-что-переключение-режима-удалит-комментарии" aria-label="Permalink to &quot;Ошибка 3: Боитесь, что переключение режима удалит комментарии&quot;">​</a></h3><p><strong>Симптом</strong></p><p>Не решаетесь переключать тип diff, опасаясь потери добавленных комментариев.</p><p><strong>Причина</strong></p><p>Неправильное понимание механизма переключения.</p><p><strong>На самом деле</strong></p><p>При переключении типа diff Plannotator сохраняет предыдущие комментарии — они могут остаться актуальными, или вы можете вручную удалить неактуальные.</p><h2 id="итоги-урока" tabindex="-1">Итоги урока <a class="header-anchor" href="#итоги-урока" aria-label="Permalink to &quot;Итоги урока&quot;">​</a></h2><p>5 типов diff, поддерживаемых Plannotator:</p><table tabindex="0"><thead><tr><th>Тип</th><th>Git-команда</th><th>Сценарий</th></tr></thead><tbody><tr><td>Uncommitted</td><td><code>git diff HEAD</code></td><td>Ревью всех изменений текущей разработки</td></tr><tr><td>Staged</td><td><code>git diff --staged</code></td><td>Проверка staging area перед коммитом</td></tr><tr><td>Unstaged</td><td><code>git diff</code></td><td>Ревью изменений в рабочей директории</td></tr><tr><td>Last commit</td><td><code>git diff HEAD~1..HEAD</code></td><td>Откат или проверка последнего коммита</td></tr><tr><td>vs main</td><td><code>git diff main..HEAD</code></td><td>Полная проверка перед слиянием ветки</td></tr></tbody></table><p>Переключение режимов не удаляет комментарии — вы можете просматривать те же или новые комментарии с разных ракурсов.</p><h2 id="анонс-следующего-урока" tabindex="-1">Анонс следующего урока <a class="header-anchor" href="#анонс-следующего-урока" aria-label="Permalink to &quot;Анонс следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../../advanced/url-sharing/">Шаринг по URL</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как сжать содержимое ревью в URL для отправки коллегам</li><li>Как получатель открывает общую ссылку на ревью</li><li>Ограничения и особенности режима шаринга</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: Справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы посмотреть расположение в исходном коде</strong></summary><blockquote><p>Дата обновления: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Функциональность</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Определение типов Diff</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L10-L15" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>10-15</td></tr><tr><td>Получение Git-контекста</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L79-L96" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>79-96</td></tr><tr><td>Выполнение Git Diff</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L101-L147" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>101-147</td></tr><tr><td>Обработка переключения Diff</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L300-L331" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>300-331</td></tr><tr><td>Рендеринг опций Diff в дереве файлов</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/components/FileTree.tsx" target="_blank" rel="noreferrer"><code>packages/review-editor/components/FileTree.tsx</code></a></td><td>-</td></tr></tbody></table><p><strong>Ключевые типы</strong>:</p><ul><li><code>DiffType</code>: <code>&#39;uncommitted&#39; | &#39;staged&#39; | &#39;unstaged&#39; | &#39;last-commit&#39; | &#39;branch&#39;</code></li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>getGitContext()</code>: Получение текущей ветки, основной ветки и доступных опций diff</li><li><code>runGitDiff(diffType, defaultBranch)</code>: Выполнение соответствующей git-команды в зависимости от типа diff</li></ul><p><strong>Ключевые API</strong>:</p><ul><li><code>POST /api/diff/switch</code>: Переключение типа diff, возврат новых данных diff</li></ul></details>',83)])])}const f=a(d,[["render",r]]);export{g as __pageData,f as default};
